'use client'
import { useRouter } from "next/navigation"

export default function AnimatedLink({
  href,
  children,
}: {
  href: string
  children: React.ReactNode
}) {
  const router = useRouter()

  const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault()

    const wrapper = document.querySelector(".page-wrapper")
    if (wrapper) {
      wrapper.classList.remove("enter-active")
      wrapper.classList.add("exit-active")

      // aguarda o tempo da animação antes de navegar
      setTimeout(() => router.push(href), 400)
    } else {
      router.push(href)
    }
  }

  return (
    <a href={href} onClick={handleClick} className="navbar__menu-link">
      {children}
    </a>
  )
}
